import java.util.*;
public class MergeSort {
    static void mergeSort(int[] a, int l, int r){if(l>=r)return;int m=(l+r)/2;mergeSort(a,l,m);mergeSort(a,m+1,r);merge(a,l,m,r);}
    static void merge(int[] a,int l,int m,int r){int[] tmp=Arrays.copyOfRange(a,l,r+1);int i=0,j=m-l+1,k=l;while(i<=m-l&&j<=r-l){if(tmp[i]<=tmp[j])a[k++]=tmp[i++];else a[k++]=tmp[j++];}while(i<=m-l)a[k++]=tmp[i++];while(j<=r-l)a[k++]=tmp[j++];}
    public static void main(String[] a){int[] arr={64,34,25,12,22,11,90};mergeSort(arr,0,arr.length-1);System.out.println(Arrays.toString(arr));System.out.println("O(n log n) time O(n) space — stable sort. Best for linked lists.");}
}

import java.util.*;
public class QuickSort {
    static void qsort(int[] a, int lo, int hi){if(lo>=hi)return;int p=partition(a,lo,hi);qsort(a,lo,p-1);qsort(a,p+1,hi);}
    static int partition(int[] a, int lo, int hi){int pivot=a[hi],i=lo;for(int j=lo;j<hi;j++)if(a[j]<=pivot){int t=a[i];a[i]=a[j];a[j]=t;i++;}int t=a[i];a[i]=a[hi];a[hi]=t;return i;}
    public static void main(String[] a){int[] arr={10,7,8,9,1,5};qsort(arr,0,arr.length-1);System.out.println(Arrays.toString(arr));System.out.println("O(n log n) avg O(n²) worst. O(log n) space. Unstable. Cache-friendly.");}
}

import java.util.*;
public class CountingSort {
    static int[] countSort(int[] a, int max){int[] cnt=new int[max+1];for(int x:a)cnt[x]++;for(int i=1;i<=max;i++)cnt[i]+=cnt[i-1];int[] out=new int[a.length];for(int i=a.length-1;i>=0;i--)out[--cnt[a[i]]]=a[i];return out;}
    public static void main(String[] a){int[] arr={4,2,2,8,3,3,1};System.out.println(Arrays.toString(countSort(arr,8)));System.out.println("O(n+k) time O(n+k) space. k=range. Stable. No comparisons.");}
}

public class SortColors {
    static void sortColors(int[] a){int lo=0,mid=0,hi=a.length-1;while(mid<=hi){if(a[mid]==0){int t=a[lo];a[lo]=a[mid];a[mid]=t;lo++;mid++;}else if(a[mid]==1)mid++;else{int t=a[mid];a[mid]=a[hi];a[hi]=t;hi--;}}
    }
    public static void main(String[] a){int[] arr={2,0,2,1,1,0};sortColors(arr);System.out.println(java.util.Arrays.toString(arr));System.out.println("O(n) O(1) — 3-way partition. mid advances only on 0 or 1, NOT after swap with hi.");}
}

import java.util.*;
public class MergeIntervals {
    static int[][] merge(int[][] intervals){Arrays.sort(intervals,(a,b)->a[0]-b[0]);List<int[]> res=new ArrayList<>();for(int[] iv:intervals){if(res.isEmpty()||res.get(res.size()-1)[1]<iv[0])res.add(iv);else res.get(res.size()-1)[1]=Math.max(res.get(res.size()-1)[1],iv[1]);}return res.toArray(new int[0][]);}
    public static void main(String[] a){System.out.println(Arrays.deepToString(merge(new int[][]{{1,3},{2,6},{8,10},{15,18}})));System.out.println(Arrays.deepToString(merge(new int[][]{{1,4},{4,5}})));System.out.println("Sort by start; merge if overlap (prev.end >= curr.start).");}
}

import java.util.*;
public class SortByFreq {
    static int[] sortByFreq(int[] nums){Map<Integer,Integer> freq=new HashMap<>();for(int n:nums)freq.merge(n,1,Integer::sum);Integer[] boxed=new Integer[nums.length];for(int i=0;i<nums.length;i++)boxed[i]=nums[i];Arrays.sort(boxed,(a,b)->freq.get(a).equals(freq.get(b))?b-a:freq.get(a)-freq.get(b));int[] res=new int[nums.length];for(int i=0;i<nums.length;i++)res[i]=boxed[i];return res;}
    public static void main(String[] a){System.out.println(Arrays.toString(sortByFreq(new int[]{1,1,2,2,2,3})));System.out.println(Arrays.toString(sortByFreq(new int[]{2,3,1,3,2})));System.out.println("Sort by freq ascending; tie-break by value descending. O(n log n)");}
}

import java.util.*;
public class LargestNum {
    static String largestNumber(int[] nums){String[] s=new String[nums.length];for(int i=0;i<nums.length;i++)s[i]=String.valueOf(nums[i]);Arrays.sort(s,(a,b)->(b+a).compareTo(a+b));if(s[0].equals("0"))return "0";return String.join("",s);}
    public static void main(String[] a){System.out.println(largestNumber(new int[]{10,2}));System.out.println(largestNumber(new int[]{3,30,34,5,9}));System.out.println("Comparator: prefer (b+a) over (a+b). Edge: all zeros → '0'.");}
}

import java.util.*;
public class MinPlatforms {
    static int minPlatforms(int[] arr, int[] dep){int n=arr.length;Arrays.sort(arr);Arrays.sort(dep);int plat=1,max=1,i=1,j=0;while(i<n&&j<n){if(arr[i]<=dep[j]){plat++;i++;}else{plat--;j++;}max=Math.max(max,plat);}return max;}
    public static void main(String[] a){System.out.println(minPlatforms(new int[]{900,940,950,1100,1500,1800},new int[]{910,1200,1120,1130,1900,2000}));System.out.println("3 — two-pointer on sorted arrivals/departures. Equivalent to Meeting Rooms II.");}
}

public class CountInversions {
    static long invCount=0;
    static void mergeSort(int[] a,int l,int r){if(l>=r)return;int m=(l+r)/2;mergeSort(a,l,m);mergeSort(a,m+1,r);merge(a,l,m,r);}
    static void merge(int[] a,int l,int m,int r){int[] tmp=java.util.Arrays.copyOfRange(a,l,r+1);int i=0,j=m-l+1,k=l;while(i<=m-l&&j<=r-l){if(tmp[i]<=tmp[j])a[k++]=tmp[i++];else{invCount+=m-l-i+1;a[k++]=tmp[j++];}}while(i<=m-l)a[k++]=tmp[i++];while(j<=r-l)a[k++]=tmp[j++];}
    public static void main(String[] a){int[] arr={8,6,2,5};invCount=0;mergeSort(arr,0,arr.length-1);System.out.println(invCount);System.out.println("5 — during merge, when right element taken: all remaining left elements are inversions. O(n log n)");}
}

import java.util.*;
public class ThreeWaySort {
    static void sort(int[] a,int lo,int hi){if(lo>=hi)return;int lt=lo,gt=hi,i=lo+1,pivot=a[lo];while(i<=gt){if(a[i]<pivot){int t=a[lt];a[lt]=a[i];a[i]=t;lt++;i++;}else if(a[i]>pivot){int t=a[i];a[i]=a[gt];a[gt]=t;gt--;}else i++;}sort(a,lo,lt-1);sort(a,gt+1,hi);}
    public static void main(String[] a){int[] arr={4,2,3,4,1,2,4,3};sort(arr,0,arr.length-1);System.out.println(Arrays.toString(arr));System.out.println("3-way quicksort: O(n log n) avg; O(n) when many duplicates (Dutch flag partition).");}
}

import java.util.*;
public class SortSynth {
    static void mergeS(int[] a,int l,int r){if(l>=r)return;int m=(l+r)/2;mergeS(a,l,m);mergeS(a,m+1,r);int[] t=Arrays.copyOfRange(a,l,r+1);int i=0,j=m-l+1,k=l;while(i<=m-l&&j<=r-l){if(t[i]<=t[j])a[k++]=t[i++];else a[k++]=t[j++];}while(i<=m-l)a[k++]=t[i++];while(j<=r-l)a[k++]=t[j++];}
    static int[][] mergeIvs(int[][] ivs){Arrays.sort(ivs,(a,b)->a[0]-b[0]);List<int[]> res=new ArrayList<>();for(int[] iv:ivs){if(res.isEmpty()||res.get(res.size()-1)[1]<iv[0])res.add(iv);else res.get(res.size()-1)[1]=Math.max(res.get(res.size()-1)[1],iv[1]);}return res.toArray(new int[0][]);}
    static String largestNum(int[] nums){String[] s=new String[nums.length];for(int i=0;i<nums.length;i++)s[i]=String.valueOf(nums[i]);Arrays.sort(s,(a,b)->(b+a).compareTo(a+b));if(s[0].equals("0"))return "0";return String.join("",s);}
    public static void main(String[] a){int[] arr={64,34,25,12,22};mergeS(arr,0,arr.length-1);System.out.println(Arrays.toString(arr));System.out.println(Arrays.deepToString(mergeIvs(new int[][]{{1,3},{2,6},{8,10}})));System.out.println(largestNum(new int[]{3,30,34,5,9}));boolean ok=arr[0]==12&&largestNum(new int[]{3,30,34,5,9}).equals("9534330");System.out.println("All pass: "+ok);}
}

